 22	} from '@patternfly/react-charts/victory';
 23	import {
 24	  Card,
 25	  CardBody,
 26	  CardHeader,
 27	  CardTitle,
 28	  Grid,
 29	  GridItem,
 30	  Button,
 31	  ButtonVariant,
 32	  EmptyState,
 33	  EmptyStateVariant,
 34	  EmptyStateIcon,
 35	  EmptyStateBody,
 36	  EmptyStateHeader,
 37	  Title,
 38	  Text,
 39	  TextVariants,
 40	} from '@patternfly/react-core';
 41	import { ArrowRightIcon, SpaceShuttleIcon } from '@patternfly/react-icons';
 42	import {
 43	  useHealthAlerts,
 44	  useSilencedAlerts,
 45	  filterOutSilencedAlerts,
 46	} from '../../HealthOverview/hooks';
 47	import './health-overview-card.scss';
 48	
 49	type HealthDataPoint = {
 50	  x: number;
 51	  y: number;
 52	  name: string;
 53	};
 54	
 55	export const HealthOverviewCard: React.FC = () => {
 56	  const { t } = useCustomTranslation();
 57	  const navigate = useNavigate();
 58	  const [chartRef, chartWidth] = useRefWidth();
 59	  const basePath = usePrometheusBasePath();
 60	
 61	  // Fetch health score metric over time (range query)
 62	  const [healthScoreData, healthScoreError, healthScoreLoading] =
 63	    useCustomPrometheusPoll({
 64	      query: HEALTH_SCORE_QUERY,
 65	      endpoint: PrometheusEndpoint.QUERY_RANGE,
 66	      basePath,
 67	      timespan: TWENTY_FOUR_HOURS,
 68	    });
 69	
 70	  // Fetch alerts for counting active issues by severity
 71	  const [healthAlerts, healthAlertsLoaded, healthAlertsError] =
 72	    useHealthAlerts();
 73	  const { silences, silencedAlertsLoaded, silencedAlertsError } =
 74	    useSilencedAlerts();
 75	
 76	  // Filter out silenced alerts and count by severity
 77	  const { criticalCount, moderateCount, minorCount } = React.useMemo(() => {
 78	    // Get active alerts (exclude silenced ones)
 79	    const activeAlerts = filterOutSilencedAlerts(healthAlerts, silences);
 80	
 81	    // Count firing alerts by severity in a single pass (O(n) instead of O(4n))
 82	    return activeAlerts.reduce(
 83	      (acc, alert) => {
 84	        // Only count firing alerts
 85	        if (alert.state !== 'firing') {
 86	          return acc;
 87	        }
 88	
 89	        // Count by severity
 90	        if (alert.severity === AlertSeverity.Critical) {
 91	          acc.criticalCount++;
 92	        } else if (alert.severity === AlertSeverity.Warning) {
 93	          acc.moderateCount++;
 94	        } else if (alert.severity === AlertSeverity.Info) {
 95	          acc.minorCount++;
 96	        }
 97	
 98	        return acc;
 99	      },
100	      { criticalCount: 0, moderateCount: 0, minorCount: 0 }
101	    );
102	  }, [healthAlerts, silences]);
103	
104	  // Process health score data for chart
105	  const chartData: HealthDataPoint[] = React.useMemo(() => {
106	    if (!healthScoreData?.data?.result?.[0]?.values) return [];
107	
108	    return healthScoreData.data.result[0].values
109	      .map((value): HealthDataPoint | null => {
110	        const [timestamp, scoreValue] = value;
111	        const score = parseFloat(scoreValue);
112	        if (Number.isNaN(score)) {
113	          return null;
114	        }
115	        const date = new Date(timestamp * 1000);
116	
117	        return {
118	          x: timestamp * 1000, // Use milliseconds for x-axis
119	          y: score,
120	          name: `${score.toFixed(1)}% at ${date.toLocaleTimeString()}`,
121	        };
122	      })
123	      .filter((item): item is HealthDataPoint => item !== null);
124	  }, [healthScoreData]);
125	
126	  // Get current health score (latest value)
127	  const currentHealthScore =
128	    chartData.length > 0 ? chartData[chartData.length - 1].y : null;
129	
130	  // Calculate fixed 24-hour x-axis domain (now - 24h to now)
131	  const xDomain = React.useMemo((): [number, number] => {
132	    const now = Date.now();
133	    return [now - TWENTY_FOUR_HOURS, now];
134	  }, []);
135	
136	  // Comprehensive loading and error state management
137	  const isAlertsLoading = !healthAlertsLoaded || !silencedAlertsLoaded;
138	  const isLoading = healthScoreLoading || isAlertsLoading;
139	
140	  const hasError = healthScoreError || healthAlertsError || silencedAlertsError;
141	  const hasNoData = chartData.length === 0;
142	  const showEmptyState = isLoading || hasError || hasNoData;
143	
144	  // Determine specific error message
145	  const getErrorMessage = () => {
146	    if (healthScoreError) {
147	      return t('Unable to retrieve health check data.');
148	    }
149	    if (healthAlertsError) {
150	      return t('Unable to retrieve alert data.');
151	    }
152	    if (silencedAlertsError) {
153	      return t('Unable to retrieve silenced alert data.');
154	    }
155	    return t(
156	      'Health check metrics are being collected. This may take a few moments.'
157	    );
158	  };
159	
160	  const cardTitle = t('Infrastructure health');
161	
162	  if (showEmptyState) {
163	    return (
164	      <Card>
165	        <CardHeader>
166	          <CardTitle>{cardTitle}</CardTitle>
167	        </CardHeader>
168	        <CardBody>
169	          <EmptyState variant={EmptyStateVariant.lg}>
170	            <EmptyStateHeader
171	              titleText={t('Waiting for health checks')}
172	              icon={<EmptyStateIcon icon={SpaceShuttleIcon} />}
173	              headingLevel="h4"
174	            />
175	            <EmptyStateBody>{getErrorMessage()}</EmptyStateBody>
176	          </EmptyState>
177	        </CardBody>
178	      </Card>
179	    );
180	  }
181	
182	  return (
183	    <Card className="odf-infrastructure-health-card">
184	      <CardHeader>
185	        <CardTitle>{cardTitle}</CardTitle>
186	      </CardHeader>
187	      <CardBody>
188	        <Grid hasGutter>
189	          {/* Health Score and Chart Row */}
190	          <GridItem md={3} sm={12}>
191	            <div className="odf-infrastructure-health-card__score">
192	              {currentHealthScore !== null ? (
193	                <>
194	                  <Title headingLevel="h2" size="3xl">
195	                    {Math.round(currentHealthScore)}%
196	                  </Title>
197	                  <Text component={TextVariants.small}>
198	                    {t('Health Score')}
199	                  </Text>
200	                </>
201	              ) : (
202	                <Text component={TextVariants.small}>{t('No data')}</Text>
203	              )}
204	            </div>
205	          </GridItem>
206	
207	          <GridItem md={9} sm={12} ref={chartRef}>
208	            {chartData.length > 0 ? (
209	              <div className="odf-infrastructure-health-card__chart">
210	                <Text component={TextVariants.small}>{t('Last 24 hours')}</Text>
211	                <Chart
212	                  ariaTitle={t('Health Score Over Time')}
213	                  containerComponent={
214	                    <ChartVoronoiContainer
215	                      labels={({ datum }) => datum.name}
216	                      constrainToVisibleArea
217	                    />
218	                  }
219	                  height={200}
220	                  width={chartWidth > 0 ? chartWidth - 40 : 600}
221	                  padding={{ top: 20, bottom: 40, left: 10, right: 10 }}
222	                  minDomain={{ x: xDomain[0], y: 0 }}
223	                  maxDomain={{ x: xDomain[1], y: 100 }}
224	                  scale={{ x: 'time', y: 'linear' }}
225	                  themeColor={ChartThemeColor.blue}
226	                >
227	                  <ChartAxis
228	                    tickFormat={(timestamp) => {
229	                      const date = new Date(timestamp);
230	                      return date.toLocaleTimeString([], {
231	                        hour: '2-digit',
232	                        minute: '2-digit',
233	                        hour12: true,
234	                      });
235	                    }}
236	                    fixLabelOverlap
237	                    style={{
238	                      axis: { stroke: 'transparent' },
239	                      tickLabels: {
240	                        fontSize: 12,
241	                        fill: 'var(--pf-t--global--text--color--subtle)',
242	                      },
243	                    }}
244	                  />
245	                  <ChartGroup>
246	                    <ChartArea
247	                      data={chartData}
248	                      interpolation="monotoneX"
249	                      style={{
250	                        data: {
251	                          fill: 'var(--pf-v6-chart-color-blue-300)',
252	                          fillOpacity: 0.3,
253	                          stroke: 'var(--pf-v6-chart-color-blue-400)',
254	                          strokeWidth: 2,
255	                        },
256	                      }}
257	                    />
258	                  </ChartGroup>
259	                </Chart>
260	              </div>
261	            ) : (
262	              <Text
263	                component={TextVariants.small}
264	                className="pf-v6-u-text-align-center"
265	              >
266	                {t('No chart data available')}
267	              </Text>
268	            )}
269	          </GridItem>
270	
271	          {/* Active Issues Section */}
272	          <GridItem md={12}>
273	            <Title headingLevel="h3" size="md">
274	              {t('Active issues')}
275	            </Title>
276	          </GridItem>
277	
278	          {[
279	            { count: criticalCount, label: 'Critical' },
280	            { count: moderateCount, label: 'Moderate' },
281	            { count: minorCount, label: 'Minor' },
282	          ].map(({ count, label }) => (
283	            <GridItem key={label} md={4} sm={4}>
284	              <Title headingLevel="h4" size="2xl">
285	                {count}
286	              </Title>
287	              <Text component={TextVariants.small}>{t(label)}</Text>
288	            </GridItem>
289	          ))}
290	
291	          {/* Action Link */}
292	          <GridItem md={12}>
293	            <Button
294	              variant={ButtonVariant.link}
295	              icon={<ArrowRightIcon />}
296	              iconPosition="end"
297	              className="pf-v6-u-font-size-lg"
298	              component="a"
299	              onClick={() => navigate('/odf/overview/health')}
300	            >
301	              {t('View health checks')}
302	            </Button>
303	          </GridItem>
304	        </Grid>
305	      </CardBody>
306	    </Card>
307	  );
308	};

