  2	import { HEALTH_SCORE_QUERY } from '@odf/core/components/odf-dashboard/queries';
  3	import { TWENTY_FOUR_HOURS } from '@odf/shared/constants';
  4	import {
  5	  useCustomPrometheusPoll,
