  3	import { TWENTY_FOUR_HOURS } from '@odf/shared/constants';
  4	import {
  5	  useCustomPrometheusPoll,
  6	  usePrometheusBasePath,
  7	} from '@odf/shared/hooks/custom-prometheus-poll';
  8	import useRefWidth from '@odf/shared/hooks/ref-width';
  9	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 10	import {
 11	  AlertSeverity,
 12	  PrometheusEndpoint,
 13	} from '@openshift-console/dynamic-plugin-sdk';
 14	import { useNavigate } from 'react-router-dom-v5-compat';
 15	import {
 16	  Chart,
 17	  ChartArea,
 18	  ChartAxis,
 19	  ChartGroup,
 20	  ChartThemeColor,
 21	  ChartVoronoiContainer,
 22	} from '@patternfly/react-charts/victory';
 23	import {
 24	  Card,
 25	  CardBody,
 26	  CardHeader,
 27	  CardTitle,
 28	  Grid,
 29	  GridItem,
 30	  Button,
 31	  ButtonVariant,
 32	  EmptyState,
 33	  EmptyStateVariant,
 34	  EmptyStateBody,
 35	  Title,
 36	  Text,
 37	  TextVariants,
 38	} from '@patternfly/react-core';
 39	import { ArrowRightIcon, SpaceShuttleIcon } from '@patternfly/react-icons';
 40	import {
 41	  useHealthAlerts,
 42	  useSilencedAlerts,
 43	  filterOutSilencedAlerts,
 44	} from '../../HealthOverview/hooks';
 45	import './health-overview-card.scss';
 46	
 47	type HealthDataPoint = {
 48	  x: number;
 49	  y: number;
 50	  name: string;
 51	};
 52	
 53	export const HealthOverviewCard: React.FC = () => {
 54	  const { t } = useCustomTranslation();
 55	  const navigate = useNavigate();
 56	  const [chartRef, chartWidth] = useRefWidth();
 57	  const basePath = usePrometheusBasePath();
 58	
 59	  // Fetch health score metric over time (range query)
 60	  const [healthScoreData, healthScoreError, healthScoreLoading] =
 61	    useCustomPrometheusPoll({
 62	      query: HEALTH_SCORE_QUERY,
 63	      endpoint: PrometheusEndpoint.QUERY_RANGE,
 64	      basePath,
 65	      timespan: TWENTY_FOUR_HOURS,
 66	    });
 67	
 68	  // Fetch alerts for counting active issues by severity
 69	  const [healthAlerts, healthAlertsLoaded, healthAlertsError] =
 70	    useHealthAlerts();
 71	  const { silences, silencedAlertsLoaded, silencedAlertsError } =
 72	    useSilencedAlerts();
 73	
 74	  // Filter out silenced alerts and count by severity
 75	  const { criticalCount, moderateCount, minorCount } = React.useMemo(() => {
 76	    // Get active alerts (exclude silenced ones)
 77	    const activeAlerts = filterOutSilencedAlerts(healthAlerts, silences);
 78	
 79	    // Count firing alerts by severity in a single pass (O(n) instead of O(4n))
 80	    return activeAlerts.reduce(
 81	      (acc, alert) => {
 82	        // Only count firing alerts
 83	        if (alert.state !== 'firing') {
 84	          return acc;
 85	        }
 86	
 87	        // Count by severity
 88	        if (alert.severity === AlertSeverity.Critical) {
 89	          acc.criticalCount++;
 90	        } else if (alert.severity === AlertSeverity.Warning) {
 91	          acc.moderateCount++;
 92	        } else if (alert.severity === AlertSeverity.Info) {
 93	          acc.minorCount++;
 94	        }
 95	
 96	        return acc;
 97	      },
 98	      { criticalCount: 0, moderateCount: 0, minorCount: 0 }
 99	    );
100	  }, [healthAlerts, silences]);
101	
102	  // Process health score data for chart
103	  const chartData: HealthDataPoint[] = React.useMemo(() => {
104	    if (!healthScoreData?.data?.result?.[0]?.values) return [];
105	
106	    return healthScoreData.data.result[0].values
107	      .map((value): HealthDataPoint | null => {
108	        const [timestamp, scoreValue] = value;
109	        const score = parseFloat(scoreValue);
110	        if (Number.isNaN(score)) {
111	          return null;
112	        }
113	        const date = new Date(timestamp * 1000);
114	
115	        return {
116	          x: timestamp * 1000, // Use milliseconds for x-axis
117	          y: score,
118	          name: `${score.toFixed(1)}% at ${date.toLocaleTimeString()}`,
119	        };
120	      })
121	      .filter((item): item is HealthDataPoint => item !== null);
122	  }, [healthScoreData]);
123	
124	  // Get current health score (latest value)
125	  const currentHealthScore =
126	    chartData.length > 0 ? chartData[chartData.length - 1].y : null;
127	
128	  // Calculate fixed 24-hour x-axis domain (now - 24h to now)
129	  const xDomain = React.useMemo((): [number, number] => {
130	    const now = Date.now();
131	    return [now - TWENTY_FOUR_HOURS, now];
132	  }, []);
133	
134	  // Comprehensive loading and error state management
135	  const isAlertsLoading = !healthAlertsLoaded || !silencedAlertsLoaded;
136	  const isLoading = healthScoreLoading || isAlertsLoading;
137	
138	  const hasError = healthScoreError || healthAlertsError || silencedAlertsError;
139	  const hasNoData = chartData.length === 0;
140	  const showEmptyState = isLoading || hasError || hasNoData;
141	
142	  // Determine specific error message
143	  const getErrorMessage = () => {
144	    if (healthScoreError) {
145	      return t('Unable to retrieve health check data.');
146	    }
147	    if (healthAlertsError) {
148	      return t('Unable to retrieve alert data.');
149	    }
150	    if (silencedAlertsError) {
151	      return t('Unable to retrieve silenced alert data.');
152	    }
153	    return t(
154	      'Health check metrics are being collected. This may take a few moments.'
155	    );
156	  };
157	
158	  const cardTitle = t('Infrastructure health');
159	
160	  if (showEmptyState) {
161	    return (
162	      <Card>
163	        <CardHeader>
164	          <CardTitle>{cardTitle}</CardTitle>
165	        </CardHeader>
166	        <CardBody>
167	          <EmptyState
168	            variant={EmptyStateVariant.lg}
169	            titleText={t('Waiting for health checks')}
170	            icon={SpaceShuttleIcon}
171	            headingLevel="h4"
172	          >
173	            <EmptyStateBody>{getErrorMessage()}</EmptyStateBody>
174	          </EmptyState>
175	        </CardBody>
176	      </Card>
177	    );
178	  }
179	
180	  return (
181	    <Card className="odf-infrastructure-health-card">
182	      <CardHeader>
183	        <CardTitle>{cardTitle}</CardTitle>
184	      </CardHeader>
185	      <CardBody>
186	        <Grid hasGutter>
187	          {/* Health Score and Chart Row */}
188	          <GridItem md={3} sm={12}>
189	            <div className="odf-infrastructure-health-card__score">
190	              {currentHealthScore !== null ? (
191	                <>
192	                  <Title headingLevel="h2" size="3xl">
193	                    {Math.round(currentHealthScore)}%
194	                  </Title>
195	                  <Text component={TextVariants.small}>
196	                    {t('Health Score')}
197	                  </Text>
198	                </>
199	              ) : (
200	                <Text component={TextVariants.small}>{t('No data')}</Text>
201	              )}
202	            </div>
203	          </GridItem>
204	
205	          <GridItem md={9} sm={12} ref={chartRef}>
206	            {chartData.length > 0 ? (
207	              <div className="odf-infrastructure-health-card__chart">
208	                <Text component={TextVariants.small}>{t('Last 24 hours')}</Text>
209	                <Chart
210	                  ariaTitle={t('Health Score Over Time')}
211	                  containerComponent={
212	                    <ChartVoronoiContainer
213	                      labels={({ datum }) => datum.name}
214	                      constrainToVisibleArea
215	                    />
216	                  }
217	                  height={200}
218	                  width={chartWidth > 0 ? chartWidth - 40 : 600}
219	                  padding={{ top: 20, bottom: 40, left: 10, right: 10 }}
220	                  minDomain={{ x: xDomain[0], y: 0 }}
221	                  maxDomain={{ x: xDomain[1], y: 100 }}
222	                  scale={{ x: 'time', y: 'linear' }}
223	                  themeColor={ChartThemeColor.blue}
224	                >
225	                  <ChartAxis
226	                    tickFormat={(timestamp) => {
227	                      const date = new Date(timestamp);
228	                      return date.toLocaleTimeString([], {
229	                        hour: '2-digit',
230	                        minute: '2-digit',
231	                        hour12: true,
232	                      });
233	                    }}
234	                    fixLabelOverlap
235	                    style={{
236	                      axis: { stroke: 'transparent' },
237	                      tickLabels: {
238	                        fontSize: 12,
239	                        fill: 'var(--pf-t--global--text--color--subtle)',
240	                      },
241	                    }}
242	                  />
243	                  <ChartGroup>
244	                    <ChartArea
245	                      data={chartData}
246	                      interpolation="monotoneX"
247	                      style={{
248	                        data: {
249	                          fill: 'var(--pf-v6-chart-color-blue-300)',
250	                          fillOpacity: 0.3,
251	                          stroke: 'var(--pf-v6-chart-color-blue-400)',
252	                          strokeWidth: 2,
253	                        },
254	                      }}
255	                    />
256	                  </ChartGroup>
257	                </Chart>
258	              </div>
259	            ) : (
260	              <Text
261	                component={TextVariants.small}
262	                className="pf-v6-u-text-align-center"
263	              >
264	                {t('No chart data available')}
265	              </Text>
266	            )}
267	          </GridItem>
268	
269	          {/* Active Issues Section */}
270	          <GridItem md={12}>
271	            <Title headingLevel="h3" size="md">
272	              {t('Active issues')}
273	            </Title>
274	          </GridItem>
275	
276	          {[
277	            { count: criticalCount, label: 'Critical' },
278	            { count: moderateCount, label: 'Moderate' },
279	            { count: minorCount, label: 'Minor' },
280	          ].map(({ count, label }) => (
281	            <GridItem key={label} md={4} sm={4}>
282	              <Title headingLevel="h4" size="2xl">
283	                {count}
284	              </Title>
285	              <Text component={TextVariants.small}>{t(label)}</Text>
286	            </GridItem>
287	          ))}
288	
289	          {/* Action Link */}
290	          <GridItem md={12}>
291	            <Button
292	              variant={ButtonVariant.link}
293	              icon={<ArrowRightIcon />}
294	              iconPosition="end"
295	              className="pf-v6-u-font-size-lg"
296	              component="a"
297	              onClick={() => navigate('/odf/overview/health')}
298	            >
299	              {t('View health checks')}
300	            </Button>
301	          </GridItem>
302	        </Grid>
303	      </CardBody>
304	    </Card>
305	  );
306	};

